assertion((await evaluate("document.querySelectorAll('.timeline-event.cna-debrief').length")) === 2 && cnaTimeline.includes("Resident completed morning care") && cnaTimeline.includes("Mary accepted eight ounces of water") && cnaTimeline.includes("Nina Alvarez"), "Resident Timeline shows every exact CNA debrief with its actor");
await clickText("View provider note", true);
assertion((await text()).includes("Signed by Dr. Hannah Cole") && !(await text()).includes("Sign and Submit for billing"), "CNA can open a signed Provider timeline note without signing controls");
await clickSelector('[aria-label="Go back"]', "CNA Provider note Back button");
await clickSelector('[aria-label="Go back"]', "CNA resident Back button");
await clickText("Margaret O'Sullivan");
await clickText("Timeline", true);
await clickText("View provider note", true);
assertion((await text()).includes("Read only for CNA") && !(await text()).includes("Sign and Submit for billing") && !(await text()).includes("Request revision"), "CNA opens an unsigned Provider timeline note in read-only mode");
await clickSelector('[aria-label="Go back"]', "CNA unsigned Provider note Back button");
await clickSelector('[aria-label="Go back"]', "CNA Margaret resident Back button");
await clickText("More", true);
assertion((await evaluate("Boolean(document.querySelector('.logout-row'))")), "CNA More includes Logout");
const preservedBeforeLogout = await evaluate(`({ encounters: JSON.parse(localStorage.getItem('sage.simple.functional.v9.encounters')).length, timeline: JSON.parse(localStorage.getItem('sage.simple.functional.v9.timeline-events')).length })`);
await clickText("Log out", true);
assertion((await text()).includes("Log out of SAGE?") && (await text()).includes("remain saved"), "Logout requires confirmation and explains data preservation");
await clickSelector('.logout-confirm-button', "CNA Logout confirmation button");
copy = await text();
assertion(copy.includes("Sign in to SAGE") && !copy.includes("Choose your SAGE role") && !copy.includes("Director of Nursing"), "Logout returns to credential sign in without role context");
const preservedAfterLogout = await evaluate(`({ encounters: JSON.parse(localStorage.getItem('sage.simple.functional.v9.encounters')).length, timeline: JSON.parse(localStorage.getItem('sage.simple.functional.v9.timeline-events')).length, signedIn: JSON.parse(localStorage.getItem('sage.simple.functional.v9.signed-in')) })`);
assertion(preservedAfterLogout.encounters === preservedBeforeLogout.encounters && preservedAfterLogout.timeline === preservedBeforeLogout.timeline && preservedAfterLogout.signedIn === null, "Logout preserves clinical activity without persisting an authenticated session");
await signIn("provider@sage.com");
assertion((await text()).includes("Your shift") && (await text()).includes("All facilities"), "Provider credentials restore All Facilities and preserved data");
await clickText("More", true);
await clickText("Settings");
await clickSelector('.font-size-options button:last-child', "Large text size before narrow-layout check");
assertion((await evaluate("document.querySelector('.mobile-prototype').classList.contains('font-size-large')")) && (await evaluate("JSON.parse(localStorage.getItem('sage.simple.functional.v9.font-size'))")) === "large", "Large text preference persists and applies to the complete app shell");

await send("Emulation.setDeviceMetricsOverride", { width: 320, height: 700, deviceScaleFactor: 1, mobile: true });
await wait(250);
const narrow = await evaluate(`({ viewport: innerWidth, body: document.body.scrollWidth, app: document.querySelector(".mobile-prototype").clientWidth, region: document.querySelector(".app-scroll-region").scrollWidth })`);
assertion(narrow.viewport === 320 && narrow.body === 320 && narrow.app === 320 && narrow.region === 320, "320px narrow-mobile layout has no horizontal overflow with Large text enabled");
await send("Emulation.setDeviceMetricsOverride", { width: 480, height: 900, deviceScaleFactor: 1, mobile: true });
await wait(250);
const intermediateMobile = await evaluate(`(() => { const app = document.querySelector('.mobile-prototype').getBoundingClientRect(); return { viewport: innerWidth, body: document.body.scrollWidth, left: Math.round(app.left), width: Math.round(app.width), right: Math.round(app.right) }; })()`);
assertion(intermediateMobile.viewport === 480 && intermediateMobile.body === 480 && intermediateMobile.left === 0 && intermediateMobile.width === 480 && intermediateMobile.right === 480, "Intermediate mobile view fills the viewport without a framed outer margin");
await send("Emulation.setDeviceMetricsOverride", { width: 320, height: 700, deviceScaleFactor: 1, mobile: true });
await wait(250);
const encountersBeforeReload = await evaluate("JSON.parse(localStorage.getItem('sage.simple.functional.v9.encounters')).length");
await evaluate("location.reload()");
await wait(600);
copy = await text();
assertion(copy.includes("Sign in to SAGE") && !copy.includes("Your shift"), "A full page reload always returns to login instead of restoring the Provider screen");
assertion((await evaluate("JSON.parse(localStorage.getItem('sage.simple.functional.v9.encounters')).length")) === encountersBeforeReload, "Starting at login does not clear persisted clinical data");
const narrowLogin = await evaluate(`({ body: document.body.scrollWidth, app: document.querySelector(".mobile-prototype").clientWidth })`);
assertion(narrowLogin.body === 320 && narrowLogin.app === 320, "The session-reset login screen has no horizontal overflow at 320px");
await send("Emulation.setDeviceMetricsOverride", { width: 480, height: 900, deviceScaleFactor: 1, mobile: true });
await wait(250);
const intermediateLogin = await evaluate(`(() => { const app = document.querySelector('.mobile-prototype').getBoundingClientRect(); return { body: document.body.scrollWidth, left: Math.round(app.left), width: Math.round(app.width) }; })()`);
assertion(intermediateLogin.body === 480 && intermediateLogin.left === 0 && intermediateLogin.width === 480, "Intermediate sign-in view also fills the viewport without an outer margin");

await send("Emulation.setDeviceMetricsOverride", { width: 1440, height: 1000, deviceScaleFactor: 1, mobile: false });
await wait(250);
const desktopLogin = await evaluate(`(() => { const card = document.querySelector('.signed-out-screen').getBoundingClientRect(); return { viewport: innerWidth, body: document.body.scrollWidth, app: document.querySelector('.mobile-prototype').clientWidth, card: Math.round(card.width), center: Math.round(card.top + card.height / 2) }; })()`);
assertion(desktopLogin.viewport === 1440 && desktopLogin.body === 1440 && desktopLogin.app === 1440 && desktopLogin.card <= 500 && Math.abs(desktopLogin.center - 500) <= 2, "Desktop login uses the full viewport and keeps its readable form vertically centered without overflow");
await signIn("provider@sage.com", "password", false);
const desktopTwoFactor = await evaluate(`(() => { const card = document.querySelector('.signed-out-screen').getBoundingClientRect(); return { copy: document.body.innerText, body: document.body.scrollWidth, width: Math.round(card.width), center: Math.round(card.top + card.height / 2) }; })()`);
assertion(desktopTwoFactor.copy.includes("Verify it’s you") && desktopTwoFactor.body === 1440 && desktopTwoFactor.width <= 500 && Math.abs(desktopTwoFactor.center - 500) <= 2, "Desktop Provider login keeps the two-factor verification step centered and overflow-free");
await completeTwoFactor("654321");
const palette = await evaluate(`(() => { const style = getComputedStyle(document.documentElement); return [style.getPropertyValue('--ink').trim(), style.getPropertyValue('--mint').trim(), style.getPropertyValue('--purple').trim()]; })()`);
assertion(JSON.stringify(palette) === JSON.stringify(["#1c192e", "#00c9a7", "#845ec2"]), "The app exposes the approved navy, mint, and purple brand palette");
const desktopShell = await evaluate(`(() => { const nav = document.querySelector('.desktop-nav'); const header = document.querySelector('.app-header'); const region = document.querySelector('.app-scroll-region'); return { navDisplay: getComputedStyle(nav).display, navWidth: Math.round(nav.getBoundingClientRect().width), headerLeft: Math.round(header.getBoundingClientRect().left), regionLeft: Math.round(region.getBoundingClientRect().left), bottomDisplay: getComputedStyle(document.querySelector('.bottom-nav')).display, facilities: document.querySelectorAll('.facility-scope-card').length, shiftColumns: getComputedStyle(document.querySelector('.facility-shift-list')).gridTemplateColumns.split(' ').length, body: document.body.scrollWidth }; })()`);
assertion(desktopShell.navDisplay === "flex" && desktopShell.navWidth === 248 && desktopShell.headerLeft === 248 && desktopShell.regionLeft === 248 && desktopShell.bottomDisplay === "none" && desktopShell.facilities === 5 && desktopShell.shiftColumns === 1 && desktopShell.body === 1440, "Desktop shell uses a persistent sidebar, aligned header/content, five facility cards, and full-width Shift facility groups without overflow");
await clickSelector('.review-note', "desktop review queue");
await clickSelector('.queue-list > button:not(:disabled)', "first desktop-ready encounter");
const desktopReviewHeader = await evaluate(`(() => { const header = document.querySelector('.task-header'); const status = document.querySelector('.task-header-status'); const headerRect = header.getBoundingClientRect(); const statusRect = status.getBoundingClientRect(); return { text: status.innerText, headerLeft: Math.round(headerRect.left), headerRight: Math.round(headerRect.right), statusRight: Math.round(statusRect.right), viewport: innerWidth }; })()`);
assertion(desktopReviewHeader.text === "Needs review" && desktopReviewHeader.headerLeft === 248 && desktopReviewHeader.headerRight === desktopReviewHeader.viewport && desktopReviewHeader.statusRight <= desktopReviewHeader.viewport, "Desktop Review and Sign keeps the Needs review status visible on the right side of the aligned header");
await evaluate("document.querySelector('.app-scroll-region').scrollTop = 420");
await wait(350);
const hiddenDesktopReviewChrome = await evaluate(`(() => { const header = document.querySelector('.task-header'); const dock = document.querySelector('.review-sign-dock'); const region = document.querySelector('.app-scroll-region').getBoundingClientRect(); return { header: header.classList.contains('hidden'), headerOpacity: getComputedStyle(header).opacity, dock: dock.classList.contains('hidden'), dockOpacity: getComputedStyle(dock).opacity, regionTop: Math.round(region.top), regionBottom: Math.round(region.bottom), viewport: innerHeight }; })()`);
assertion(hiddenDesktopReviewChrome.header && hiddenDesktopReviewChrome.headerOpacity === "0" && hiddenDesktopReviewChrome.dock && hiddenDesktopReviewChrome.dockOpacity === "0" && hiddenDesktopReviewChrome.regionTop === 0 && hiddenDesktopReviewChrome.regionBottom === hiddenDesktopReviewChrome.viewport, "Desktop Review and Sign hides both chrome regions and expands content to the viewport while scrolling down");
await evaluate("document.querySelector('.app-scroll-region').scrollTop = 0");
await wait(220);
await clickText("Residents", true);
assertion((await evaluate("getComputedStyle(document.querySelector('.resident-list')).gridTemplateColumns.split(' ').length")) === 2, "Desktop Residents uses a readable two-column directory");
await clickText("Mary Lou Smith");
assertion((await evaluate("getComputedStyle(document.querySelector('.desktop-nav')).display")) === "flex" && (await evaluate("document.querySelector('.app-scroll-region').scrollWidth <= document.querySelector('.app-scroll-region').clientWidth")), "Desktop navigation remains available on nested screens without content overflow");
await send("Emulation.setDeviceMetricsOverride", { width: 1024, height: 768, deviceScaleFactor: 1, mobile: false });
await wait(250);
const compactDesktop = await evaluate(`({ body: document.body.scrollWidth, viewport: innerWidth, nav: Math.round(document.querySelector('.desktop-nav').getBoundingClientRect().width), region: document.querySelector('.app-scroll-region').scrollWidth, regionClient: document.querySelector('.app-scroll-region').clientWidth })`);
assertion(compactDesktop.body === 1024 && compactDesktop.viewport === 1024 && compactDesktop.nav === 248 && compactDesktop.region <= compactDesktop.regionClient, "1024px desktop layout preserves the sidebar and has no horizontal overflow");

if (browserErrors.length) console.log("Browser errors:", browserErrors);
assertion(browserErrors.length === 0, "No browser exceptions or console errors were reported");
console.log("\nFunctional SAGE Simple smoke test passed.");
socket.close();
